"use client";

import { useState } from "react";
import Image from "next/image";

type LegAccordionProps = {
  topLegSrc: string;
  bottomLegSrc: string;
  children?: React.ReactNode;
};

export default function LegAccordion({
  topLegSrc,
  bottomLegSrc,
  children,
}: LegAccordionProps) {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className="relative w-full select-none z-50">
      {/* Top leg — stays fixed */}
      <div
        className="w-full cursor-pointer"
        onClick={() => setIsOpen((prev) => !prev)}
      >
        <Image
          src={topLegSrc}
          alt="Top leg"
          width={1200}
          height={300}
          className="w-full object-cover "
         
        />
      </div>

      {/* Content revealed between the legs */}
      <div
        className="w-full overflow-hidden transition-all duration-500 ease-in-out"
        style={{ maxHeight: isOpen ? "800px" : "0px" }}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="px-8 py-10">{children}</div>
      </div>

      {/* Bottom leg — slides down */}
      <div
        className="w-full transition-transform duration-500 ease-in-out cursor-pointer"
        style={{ transform: isOpen ? "translateY(100%)" : "translateY(0)" }}
        onClick={() => setIsOpen((prev) => !prev)}
      >
        <Image
          src={bottomLegSrc}
          alt="Bottom leg"
          width={1200}
          height={300}
          className="w-full object-cover -mt-4 -ml-1.5"
        
        />
      </div>

      {/* Hint */}
      <p
        className="text-center text-xs text-gray-400 mt-2 tracking-widest uppercase cursor-pointer"
        onClick={() => setIsOpen((prev) => !prev)}
      >
        {isOpen ? "click to close" : "click to open"}
      </p>
    </div>
  );
}
